2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office - Quote (Premium Calculation)", () => {
5	  // Simplest case: empty quote
6	  it.todo("should return 5G premium (just processing fee) for empty item list");
7	
8	  // Single item base premiums (no modifiers other than first-insurance per-item surcharge)
9	  it.todo("should calculate premium for a single plain sword for a newcomer");
10	  it.todo("should calculate premium for a single plain amulet for a newcomer");
11	  it.todo("should calculate premium for a single plain staff for a newcomer");
12	  it.todo("should calculate premium for a single plain potion for a newcomer");
13	  it.todo("should calculate premium for a single rune component for a newcomer");
14	  it.todo("should calculate premium for a single moonstone component for a newcomer");
15	
16	  // Multiple items, base premiums
17	  it.todo("should sum base premiums for a cursed sword plus plain amulet (before fee)");
18	  it.todo("should calculate premium for a plain sword plus plain amulet for a newcomer");
19	
20	  // Item-specific modifiers
21	  it.todo("should add 50% surcharge to base premium for a cursed item");
22	  it.todo("should add 30% surcharge to base premium for a highly enchanted item (enchantment >= 5)");
23	  it.todo("should apply both cursed and high-enchantment surcharges to the same item");
24	
25	  // Component blocks
26	  it.todo("should charge 50G for 2 runes (no block)");
27	  it.todo("should charge 60G base for 3 alike runes as a block");
28	  it.todo("should charge 100G for 4 runes (one block of 3 plus 1 single)");
29	  it.todo("should charge 175G for 7 runes (two blocks of 3 plus 1 single)");
30	  it.todo("should charge 75G for 2 runes plus 1 moonstone (no block, mixed types)");
31	  it.todo("should charge 120G for 3 runes plus 3 moonstones (two separate blocks)");
32	
33	  // Policy-wide modifiers
34	  it.todo("should apply 20% loyalty discount for long-standing customer (>= 2 years)");
35	  it.todo("should apply 10% first-insurance surcharge per item for a newcomer");
36	  it.todo("should apply 15% follow-up contract discount on subsequent quotes");
37	
38	  // Combined modifiers (canonical examples from spec)
39	  it.todo("should calculate 165G for newcomer with cursed sword (100 + 50 + 10 + 5)");
40	  it.todo("should calculate 160G for long-standing customer 2nd contract with cursed sword ench 7");
41	
42	  // Rounding
43	  it.todo("should round the final premium UP to whole G (in MHPCO's favor)");
44	  it.todo("should round 197.5G premium up to 198G");
45	});
