47	describe("MHPCO Claim Office - Claim (Damage Payout)", () => {
48	  // Simplest case
49	  it.todo("should pay out damage minus 100G deductible for a plain item");
50	  it.todo("should pay out 400G for a regular sword ench 3 with 500G damage");
51	
52	  // Component claims (no special clauses)
53	  it.todo("should pay out 100G for a rune with 200G damage (250G insured, minus deductible)");
54	
55	  // Special clauses
56	  it.todo("should reimburse 50% of damage then deduct 100G for items with enchantment >= 8");
57	  it.todo("should pay out 400G for a steel sword ench 9 with 1000G damage");
58	  it.todo("should fully reimburse dragon-material items then deduct 100G");
