60	  it.todo("should apply 50% rule (not dragon rule) when both apply, paying 400G for dragon sword ench 8 with 1000G damage");
61	
62	  // Multiple damage entries
63	  it.todo("should apply own deductible to each damage entry when one event damages multiple items");
64	
65	  // Cap (2x unmodified insurance sum)
66	  it.todo("should cap total payout at 2x sum of unmodified insurance values across the policy");
67	  it.todo("should reduce payout when remaining cap is less than computed payout");
68	  it.todo("should share the cap across multiple successive claims on the same policy");
69	
70	  // Rounding
71	  it.todo("should round the final payout DOWN to whole G");
72	  it.todo("should round a 350.5G payout down to 350G");
